import { useState } from 'react';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  Tag,
  Intent,
  Alignment,
} from '@blueprintjs/core';

type LOD = 'MACRO' | 'MESO' | 'MICRO';

function App() {
  const [zoom, setZoom] = useState(1.0);

  // Compute LOD from zoom level
  const getLOD = (z: number): LOD => {
    if (z < 0.5) return 'MACRO';
    if (z > 2.0) return 'MICRO';
    return 'MESO';
  };

  const lod = getLOD(zoom);

  const getLODIntent = (l: LOD): Intent => {
    switch (l) {
      case 'MACRO': return Intent.WARNING;
      case 'MESO': return Intent.PRIMARY;
      case 'MICRO': return Intent.SUCCESS;
    }
  };

  const handleZoomIn = () => setZoom(z => Math.min(z * 1.5, 5.0));
  const handleZoomOut = () => setZoom(z => Math.max(z / 1.5, 0.1));
  const handleReset = () => setZoom(1.0);

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Navbar>
        <NavbarGroup align={Alignment.LEFT}>
          <NavbarHeading>MMS Canvas</NavbarHeading>
          <NavbarDivider />
          <span style={{ fontFamily: 'monospace' }}>
            Zoom: {zoom.toFixed(2)}x
          </span>
          <NavbarDivider />
          <Tag intent={getLODIntent(lod)} minimal>
            {lod}
          </Tag>
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <Button icon="minus" minimal onClick={handleZoomOut} />
          <Button icon="plus" minimal onClick={handleZoomIn} />
          <NavbarDivider />
          <Button icon="reset" minimal onClick={handleReset}>
            Reset
          </Button>
        </NavbarGroup>
      </Navbar>

      <div style={{ flex: 1, display: 'flex' }}>
        {/* Sidebar placeholder */}
        <div style={{
          width: 120,
          borderRight: '1px solid #e1e8ed',
          padding: 10,
          backgroundColor: '#f5f8fa'
        }}>
          <div style={{ fontWeight: 600, marginBottom: 10 }}>Trains</div>
          {Array.from({ length: 10 }, (_, i) => (
            <div key={i} style={{ padding: '4px 0', fontSize: 12 }}>
              TRAIN-{String(i + 1).padStart(3, '0')}
            </div>
          ))}
        </div>

        {/* Canvas area placeholder */}
        <div style={{
          flex: 1,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          backgroundColor: '#f4f4f5',
          color: '#5c7080',
          fontSize: 14
        }}>
          R3F Canvas will render here (F102)
        </div>
      </div>
    </div>
  );
}

export default App;

